import React, { useState } from 'react';
import { View, Text, Button } from 'react-native';
import OAuth2 from 'oauth2-client';

const App = () => {
  const [token, setToken] = useState(null);

  const handleLogin = async () => {
    try {
      const oauthClient = new OAuth2({
        client_id: 'your_client_id',
        client_secret: 'your_client_secret',
        authorization_uri: 'https://your-oauth-server.com/authorize',
        token_uri: 'https://your-oauth-server.com/token',
      });

      const authUrl = oauthClient.getAuthorizationUrl({
        scope: ['openid', 'profile', 'email'],
      });

      const { code } = await WebBrowser.openAuthSessionAsync(authUrl);

      if (code) {
        const tokenResponse = await oauthClient.getToken(code);
        setToken(tokenResponse.access_token);
      }
    } catch (error) {
      console.log('Error:', error);
    }
  };

  return (
    <View>
      <Button title="Login" onPress={handleLogin} />
      {token && <Text>Token: {token}</Text>}
    </View>
  );
};